INSERT INTO comments (user_id, board_id, comment, time) VALUES
-- Semantic cluster: "Deploying on Friday is risky"
(12, 63, 'We have a hard rule: no deploys after Thursday noon. It has saved us more times than I can count.', NOW() - INTERVAL '142 days 8 hours 15 minutes'),
(47, 49, 'Pushed a release at 4pm on Friday once. Spent the entire weekend on a Zoom call fixing it. Never again.', NOW() - INTERVAL '98 days 14 hours 33 minutes'),
(3, 63, 'End-of-week releases are a trap. Nobody wants to debug on Saturday morning.', NOW() - INTERVAL '44 days 10 hours 5 minutes'),
(81, 24, 'Our CI/CD pipeline blocks merges to main after 2pm on Fridays. Best automation decision we ever made.', NOW() - INTERVAL '11 days 16 hours 22 minutes'),

-- Semantic cluster: "Caching invalidation is the real problem"
(55, 5, 'Getting the cache to fill is easy. Knowing when to throw it away? That is the actual engineering challenge.', NOW() - INTERVAL '177 days 3 hours 12 minutes'),
(9, 58, 'We had stale data showing up for 6 hours because nobody thought about TTLs when they set up the Redis layer.', NOW() - INTERVAL '130 days 19 hours 45 minutes'),
(34, 5, 'The two hardest problems in computer science: naming things, and making sure your cached data is still correct.', NOW() - INTERVAL '67 days 7 hours 8 minutes'),
(72, 51, 'Our users kept seeing yesterday''s prices because the CDN cache wasn''t busting properly. Took us a week to find it.', NOW() - INTERVAL '22 days 11 hours 50 minutes'),

-- Semantic cluster: "Microservices were overkill"
(18, 21, 'We split our monolith into 23 microservices. Now we have 23 problems instead of 1. Would not recommend for a team of 4.', NOW() - INTERVAL '165 days 5 hours 40 minutes'),
(63, 21, 'Distributed systems are incredible when you need them and a nightmare when you don''t. We did not need them.', NOW() - INTERVAL '110 days 22 hours 17 minutes'),
(44, 56, 'A well-structured monolith will beat a poorly designed service mesh every single time. Fight me.', NOW() - INTERVAL '55 days 14 hours 28 minutes'),
(91, 35, 'The overhead of maintaining service-to-service communication ended up costing us more than the thing we were trying to scale.', NOW() - INTERVAL '8 days 9 hours 3 minutes'),

-- Semantic cluster: "Naming things is impossibly hard"
(22, 60, 'I spent 45 minutes naming a variable today. Ended up calling it "data2" anyway. I am not proud.', NOW() - INTERVAL '170 days 12 hours 20 minutes'),
(77, 35, 'Our codebase has a function called "processStuff." Nobody knows what it does but it runs in production so we don''t touch it.', NOW() - INTERVAL '101 days 6 hours 55 minutes'),
(8, 61, 'Good naming is documentation that never goes stale. Bad naming is a riddle your coworkers have to solve at 2am.', NOW() - INTERVAL '38 days 15 hours 11 minutes'),
(50, 50, 'I renamed a module three times this week. Each name was worse than the last. I went back to the original.', NOW() - INTERVAL '5 days 4 hours 42 minutes'),

-- Semantic cluster: "Email is deceptively hard"
(15, 88, 'I thought sending email from an app was trivial. Then I learned about SPF, DKIM, DMARC, and my will to live decreased.', NOW() - INTERVAL '160 days 20 hours 30 minutes'),
(39, 88, 'Nothing humbles a backend engineer faster than trying to get transactional emails to land in the inbox instead of spam.', NOW() - INTERVAL '88 days 2 hours 14 minutes'),
(66, 88, 'We spent 3 weeks building the notification system and 2 months on email deliverability. The ratio tells you everything.', NOW() - INTERVAL '28 days 17 hours 46 minutes'),

-- Semantic cluster: "Documentation that nobody reads"
(29, 61, 'Wrote a 30-page onboarding doc. New hire''s first Slack message: "Where do I find the setup instructions?"', NOW() - INTERVAL '155 days 1 hour 10 minutes'),
(84, 38, 'We documented every single API endpoint with examples. Support tickets stayed exactly the same.', NOW() - INTERVAL '91 days 13 hours 37 minutes'),
(6, 61, 'The best documentation is the kind people actually open. Which, based on our metrics, is none of it.', NOW() - INTERVAL '43 days 8 hours 52 minutes'),
(53, 7, 'I think the only person who ever reads API docs is the person who wrote them, while proofreading.', NOW() - INTERVAL '15 days 20 hours 5 minutes'),

-- Semantic cluster: "Time zones are a nightmare"
(41, 82, 'Every time I think I understand time zones, daylight saving time proves me wrong.', NOW() - INTERVAL '148 days 6 hours 18 minutes'),
(70, 82, 'We store everything in UTC. Display in local time. This still somehow breaks twice a year.', NOW() - INTERVAL '95 days 11 hours 2 minutes'),
(19, 82, 'Our scheduling feature worked perfectly until we had users in Arizona, which doesn''t observe DST. Fun times.', NOW() - INTERVAL '30 days 22 hours 39 minutes'),
(88, 53, 'Date math is the closest software engineering gets to black magic. Just use a library. Trust me.', NOW() - INTERVAL '4 days 7 hours 15 minutes'),

-- Semantic cluster: "Premature optimization is a waste"
